// Count VALID hosts, not total hosts
const fogData = items[0].json.data;
let hostCount = 0;

// Option 1: Use valid_hosts field
if (fogData.valid_hosts !== undefined) {
  hostCount = fogData.valid_hosts;
  console.log('Using valid_hosts:', hostCount);
} 
// Option 2: Count hosts array
else if (fogData.hosts && Array.isArray(fogData.hosts)) {
  hostCount = fogData.hosts.length;
  console.log('Counting hosts array:', hostCount);
}
// Option 3: Fallback
else {
  hostCount = 1;
  console.log('Using fallback host_count:', hostCount);
}

console.log(`Processing ${hostCount} valid host(s)`);
console.log('Total hosts:', fogData.total_hosts);
console.log('Invalid hosts:', fogData.invalid_hosts);

return [{ json: { host_count: hostCount } }];

// Build PostgreSQL query with dynamic host_count
const hostCount = items[0].json.host_count;

return [{
  json: {
    query: `
      UPDATE computer_sequence 
      SET current_number = current_number + ${hostCount}, 
          last_updated = NOW()
      RETURNING current_number - ${hostCount} + 1 AS start_number, 
                current_number AS end_number;
    `,
    // Pass through other data
    hosts_data: items[0].json.hosts_data,
    glpi_ids: items[0].json.glpi_ids,
    session_token: items[0].json.session_token
  }
}];

// Generate inventory numbers for each host and store in PostgreSQL
const input = items[0].json;
const startNumber = input.start_number;
const endNumber = input.end_number || startNumber;

// Get hosts data from the correct location
const hostsData = input.data?.hosts || [];
const glpiIds = input.glpi_ids || {};
const config = input.config || {};

console.log('DEBUG: Input structure:', {
  hasData: !!input.data,
  hostsCount: hostsData.length,
  startNumber,
  endNumber,
  totalHosts: input.data?.total_hosts || 0
});

// Get current date for inventory number prefix
const now = new Date();
const month = now.getMonth() + 1;
const day = now.getDate().toString().padStart(2, '0');
const datePrefix = `${month}${day}`;

// ========== CRITICAL FIX: Use FOG prefix '6' to avoid GLPI conflicts ==========
const FOG_PREFIX = '6';
const fullPrefix = `${FOG_PREFIX}${datePrefix}`;
console.log(`Using FOG prefix: ${FOG_PREFIX}, Full prefix: ${fullPrefix}`);

// ========== Query database for existing FOG inventory numbers ==========
// We still need to check our own database to avoid duplicates within FOG system
console.log(`Checking database for existing FOG inventory numbers with prefix: ${fullPrefix}`);

// Query PostgreSQL for the highest sequence number used today for FOG
let nextSequenceNumber = 1;

if (input.max_sequence_today !== undefined && input.max_sequence_today !== null) {
  nextSequenceNumber = input.max_sequence_today + 1;
  console.log(`Found existing max FOG sequence: ${input.max_sequence_today}, starting from: ${nextSequenceNumber}`);
} else {
  console.log('No existing FOG sequence found for today, starting from 0001');
}

console.log(`Next available FOG sequence number: ${nextSequenceNumber}`);

// Check if we have enough sequence numbers for all hosts
const hostsNeeded = hostsData.length;
const sequenceNumbersAvailable = 9999 - nextSequenceNumber + 1; // We have 0000-9999 available

if (hostsNeeded > sequenceNumbersAvailable) {
  console.error(`ERROR: Need ${hostsNeeded} sequence numbers, but only have ${sequenceNumbersAvailable} available`);
  throw new Error(`Insufficient sequence numbers: need ${hostsNeeded}, have ${sequenceNumbersAvailable}`);
}

// If no hosts data, we can only generate inventory numbers
if (!hostsData || hostsData.length === 0) {
  console.log('No hosts data provided, generating inventory numbers only');

  // Generate inventory numbers for the sequence range
  const inventoryNumbers = [];
  for (let i = 0; i < sequenceNumbersAvailable; i++) {
    const sequentialNumber = nextSequenceNumber + i;
    // Format: 6 + MMDD + XXXX
    const inventoryNumber = `${fullPrefix}${sequentialNumber.toString().padStart(4, '0')}`;

    inventoryNumbers.push({
      inventory_number: inventoryNumber,
      sequence_number: sequentialNumber,
      start_number: nextSequenceNumber,
      end_number: nextSequenceNumber + sequenceNumbersAvailable - 1,
      date_prefix: datePrefix,
      fog_prefix: FOG_PREFIX,
      full_prefix: fullPrefix
    });
  }

  console.log(`Generated ${inventoryNumbers.length} FOG inventory numbers`);
  return inventoryNumbers.map(item => ({ json: item }));
}

// Prepare computers to create - match hosts with inventory numbers
const computersToCreate = [];

for (let i = 0; i < hostsData.length; i++) {
  const host = hostsData[i];
  const sequenceNumber = nextSequenceNumber + i;

  // Generate inventory number: 6MMDDXXXX
  const inventoryNumber = `${fullPrefix}${sequenceNumber.toString().padStart(4, '0')}`;

  // Extract host information
  const fogHostId = host.id;
  const hostName = host.name;
  const serialNumber = host.inventory?.sysserial || '';
  const macAddress = host.macs?.[0] || host.primac || '';
  const manufacturer = host.inventory?.sysman || '';
  const model = host.inventory?.sysversion || host.inventory?.sysproduct || '';
  const productSku = host.inventory?.sysproduct || '';
  const computerType = host.inventory?.systype || '';
  const processor = host.inventory?.cpuversion || '';
  const memory = host.inventory?.memory || '';
  const storage = host.inventory?.hdmodel || '';
  const comment = host.description || '';

  // NORMALIZE lookup keys for case-insensitive matching
  const normalizedManufacturer = (manufacturer || '').toLowerCase().trim();
  const normalizedModel = (model || '').toLowerCase().trim();
  const normalizedProductSku = (productSku || '').toLowerCase().trim();

  // Manufacturer lookup
  const manufacturerId = glpiIds.manufacturers?.[normalizedManufacturer] || 
                        glpiIds.manufacturers?.[manufacturer] || 
                        config.default_manufacturer_id || 1;

  // Model lookup - try multiple strategies
  let modelId = config.default_model_id || 1;

  // 1. Try exact model match
  if (glpiIds.models?.[normalizedModel]) {
    modelId = glpiIds.models[normalizedModel];
  } 
  // 2. Try product SKU match  
  else if (glpiIds.models?.[normalizedProductSku]) {
    modelId = glpiIds.models[normalizedProductSku];
  }
  // 3. Try partial match (contains "thinkpad")
  else if (normalizedModel.includes('thinkpad')) {
    const foundModelKey = Object.keys(glpiIds.models || {}).find(key => 
      key.includes('thinkpad')
    );
    if (foundModelKey) {
      modelId = glpiIds.models[foundModelKey];
    }
  }

  // Processor lookup
  const normalizedProcessor = (processor || '').toLowerCase().trim();
  const processorId = glpiIds.processors?.[normalizedProcessor] || 
                     glpiIds.processors?.[processor] || 
                     config.default_processor_id || 1;

  // Memory lookup
  const normalizedMemory = (memory || '').toLowerCase().trim();
  const memoryId = glpiIds.memory?.[normalizedMemory] || 
                  glpiIds.memory?.[memory] || 
                  config.default_memory_id || 1;

  // Type lookup - default to Notebook
  const typeId = glpiIds.types?.['Notebook'] || config.default_computertype_id || 1;

  // Storage lookup
  const normalizedStorage = (storage || '').toLowerCase().trim();
  const storageId = glpiIds.storage?.[normalizedStorage] || 
                   glpiIds.storage?.[storage] || 
                   config.default_storage_id || 1;

  // Get configuration with defaults
  const defaults = {
    states_id: config.states_id || 1,
    locations_id: config.locations_id || 1,
    users_id: config.users_id || 0,
    groups_id: config.groups_id || 0,
    is_dynamic: config.is_dynamic !== undefined ? config.is_dynamic : 1
  };

  computersToCreate.push({
    // Host identification
    fog_host_id: fogHostId,
    host_name: hostName,
    serial_number: serialNumber,
    mac_address: macAddress,

    // Inventory data
    inventory_number: inventoryNumber,
    sequence_number: sequenceNumber,
    date_prefix: datePrefix,
    fog_prefix: FOG_PREFIX,

    // Host details for GLPI
    manufacturer: manufacturer,
    model: model,
    processor: processor,
    memory: memory,
    storage: storage,
    comment: comment,

    // GLPI creation data with configurable values
    glpi_data: {
      name: hostName,
      serial: serialNumber,
      otherserial: inventoryNumber,  // This will be 6MMDDXXXX format
      computermodels_id: modelId,
      manufacturers_id: manufacturerId,
      computertypes_id: typeId,
      states_id: defaults.states_id,
      locations_id: defaults.locations_id,
      users_id: defaults.users_id,
      groups_id: defaults.groups_id,
      is_dynamic: defaults.is_dynamic,
      comment: comment,
      _component_ids: {
        processor: processorId,
        memory: memoryId,
        storage: storageId
      }
    },

    component_ids: {
      processor: processorId,
      memory: memoryId,
      storage: storageId
    },

    // For PostgreSQL insertion
    status: 'pending_glpi_creation',
    created_at: new Date().toISOString()
  });

  console.log(`Prepared FOG computer: ${hostName} (${serialNumber}) → ${inventoryNumber} (seq: ${sequenceNumber})`);
}

console.log(`Prepared ${computersToCreate.length} FOG computers for GLPI creation`);
console.log(`Used FOG sequence range: ${nextSequenceNumber} to ${nextSequenceNumber + hostsData.length - 1}`);
console.log(`FOG inventory number format: ${FOG_PREFIX} + MMDD + XXXX (e.g., ${fullPrefix}XXXX)`);

// Return computers for next step (PostgreSQL insertion)
return computersToCreate.map(computer => ({
  json: computer
}));

// Extract GLPI IDs and fetch component_ids from PostgreSQL
const results = items.map(item => {
  const mergedData = item.json;

  let glpiId = null;
  let success = false;

  if (mergedData.error && mergedData.error.message) {
    const errorMessage = mergedData.error.message;
    const idMatch = errorMessage.match(/ID:\s*(\d+)/);
    if (idMatch) {
      glpiId = parseInt(idMatch[1]);
      success = true;
    }
  }
  else if (mergedData.id) {
    glpiId = mergedData.id;
    success = true;
  }

  const postgresId = mergedData.postgres_id;
  const computerName = mergedData.computer_name || mergedData.host_name;
  const inventoryNumber = mergedData.inventory_number;

  return {
    json: {
      glpi_computer_id: glpiId,
      postgres_id: postgresId,
      computer_name: computerName,
      inventory_number: inventoryNumber,
      success: success,
      component_ids: null,
      _full_data: mergedData
    }
  };
});

return results;

// Use data returned from the INSERT ... RETURNING query
const results = items.map(item => {
  const input = item.json;

  const glpiData = input.glpi_data;

  // Add postgres_id to glpi_data
  glpiData._postgres_id = input.id;

  console.log(`Preparing GLPI request for computer ${input.computer_name} (ID: ${input.id})`);

  return {
    json: {
      glpi_data: glpiData,
      session_token: input.session_token,
      postgres_id: input.id,
      computer_name: input.computer_name,
      inventory_number: input.inventory_number,
      fog_host_id: input.fog_host_id
    }
  };
});

console.log(`Processed ${results.length} items for GLPI creation`);
return results;

// The PostgreSQL node returns data in a specific structure
// Based on your sample, items[0].json is the array of 158 items

console.log('=== DEBUG: Checking input structure ===');

// PostgreSQL nodes in n8n often wrap results
// Let's check ALL possible locations
if (items && items.length > 0) {
  console.log('Number of items:', items.length);

  // Check each item
  items.forEach((item, index) => {
    console.log(`\n--- Item ${index} ---`);
    console.log('Type:', typeof item);
    console.log('Keys:', Object.keys(item || {}));

    if (item.json) {
      console.log('json type:', typeof item.json);
      console.log('Is array?', Array.isArray(item.json));

      if (Array.isArray(item.json)) {
        console.log(`Array length: ${item.json.length}`);
        if (item.json.length > 0) {
          console.log('First array element:', JSON.stringify(item.json[0]));
        }
      } else {
        console.log('json content:', JSON.stringify(item.json, null, 2));
      }
    }
  });
}

// Try to find the data
let cacheResults = [];

// Method 1: Direct array in items[0].json
if (items[0] && items[0].json && Array.isArray(items[0].json)) {
  cacheResults = items[0].json;
  console.log(`Found data in items[0].json (${cacheResults.length} items)`);
} 
// Method 2: Data might be in items directly (multiple items)
else if (items.length > 1) {
  cacheResults = items.map(item => item.json).filter(Boolean);
  console.log(`Found data in multiple items (${cacheResults.length} items)`);
}
// Method 3: Check for other structures
else if (items[0] && items[0].json && items[0].json.rows) {
  cacheResults = items[0].json.rows;
  console.log(`Found data in items[0].json.rows (${cacheResults.length} items)`);
}

console.log(`\n=== Processing ${cacheResults.length} cache entries ===`);

const glpi_ids = {
  manufacturers: {},
  models: {},
  processors: {},
  memory: {},
  types: {},
  storage: {}
};

// Process the data
cacheResults.forEach((item, index) => {
  if (!item || typeof item !== 'object') {
    console.log(`Skipping invalid item at index ${index}:`, item);
    return;
  }

  // Log first few items to verify
  if (index < 5) {
    console.log(`Item ${index}:`, JSON.stringify(item));
  }

  const entityType = item.entity_type;
  const glpiId = item.glpi_id;
  const normalizedName = item.normalized_name;

  if (!entityType || !glpiId || !normalizedName) {
    console.log(`Skipping item ${index} missing fields:`, item);
    return;
  }

  // Convert to lowercase for consistency
  const key = normalizedName.toLowerCase();

  switch(entityType.toLowerCase()) {
    case 'manufacturer':
      glpi_ids.manufacturers[key] = glpiId;
      break;
    case 'model':
      glpi_ids.models[key] = glpiId;
      break;
    case 'processor':
      glpi_ids.processors[key] = glpiId;
      break;
    case 'memory':
      glpi_ids.memory[key] = glpiId;
      break;
    case 'computer_type':
      glpi_ids.types[key] = glpiId;
      break;
    case 'storage':
      glpi_ids.storage[key] = glpiId;
      break;
    default:
      console.log(`Unknown entity_type at index ${index}:`, entityType);
  }
});
// ===== PRESERVE INPUT DATA FOR DOWNSTREAM =====
// If the Merge node passed through FOG hosts data, keep it
let originalData = null;

if (items[0]?.json?.data?.hosts) {
  originalData = items[0].json.data;
  console.log(`Found FOG hosts data with ${originalData.hosts.length} hosts`);
} else if (items[0]?.json?.hosts_data) {
  originalData = { hosts: items[0].json.hosts_data };
  console.log('Found hosts_data field');
}
console.log('\n=== RESULTS ===');
console.log('Manufacturers:', glpi_ids.manufacturers);
console.log('Models:', glpi_ids.models);
console.log('Processors:', glpi_ids.processors);
console.log('Memory:', glpi_ids.memory);
console.log('Types:', glpi_ids.types);
console.log('Storage:', glpi_ids.storage);

// Check specifically for lenovo
console.log('\n=== SPECIFIC CHECKS ===');
console.log('Has "lenovo"?', 'lenovo' in glpi_ids.manufacturers);
console.log('Has "20t00074uk"?', '20t00074uk' in glpi_ids.models);
console.log('Has "15.26 gib"?', '15.26 gib' in glpi_ids.memory);
console.log('Has "notebook"?', 'notebook' in glpi_ids.types);
console.log('Has "micronmtfdhba256tdv"?', 'micronmtfdhba256tdv' in glpi_ids.storage);

return [{ 
  json: { 
    glpi_ids: glpi_ids,
    _fog_data: originalData || items[0]?.json?.data || { hosts: [] },
    session_token: items[0]?.json?.session_token
  } 
}];

// Prepare duplicate checks for raw FOG hosts
const input = items[0].json;

// Extract raw FOG host data
const fogData = input.data; // From orchestrator
const hostsData = fogData?.hosts || [];

// Get session token from GLPI Session Management
// Assuming GLPI Session Management returns { session_token: "abc123" }
const sessionToken = input.session_token;

if (!sessionToken) {
  console.error('ERROR: No session token from GLPI Session Management');
  console.log('Available keys:', Object.keys(input));
  throw new Error('Session token is required for duplicate check');
}

if (!hostsData || hostsData.length === 0) {
  console.log('No hosts data to process');
  return [{ json: { ...input, filtered_hosts: [], duplicate_check_summary: { total: 0, to_process: 0 } } }];
}

console.log(`Preparing duplicate checks for ${hostsData.length} raw FOG hosts`);

// Create one item per host for parallel duplicate checking
const duplicateCheckRequests = hostsData.map(host => {
  const serial = host.inventory?.sysserial || '';
  const hostName = host.name;
  const fogHostId = host.id;

  return {
    json: {
      // Data for HTTP request
      serial_number: serial,
      session_token: sessionToken,

      // Original raw host data
      original_host: host,
      host_name: hostName,
      fog_host_id: fogHostId,

      // Pass through other data
      _fog_data: fogData, // Keep full FOG data
      _metadata: input.metadata
    }
  };
});

console.log(`Created ${duplicateCheckRequests.length} duplicate check requests`);
return duplicateCheckRequests;

// Filter out duplicate hosts based on GLPI check
const results = items.map(item => {
  const requestData = item.json;
  const glpiResponse = item.response; // From HTTP request

  const serial = requestData.serial_number;
  const host = requestData.original_host;
  const hostName = requestData.host_name;

  console.log(`Processing duplicate check for: ${hostName} (Serial: ${serial})`);

  let existsInGLPI = false;
  let glpiComputerId = null;
  let glpiComputerData = null;

  // Check GLPI response
  if (glpiResponse && glpiResponse.data) {
    // GLPI returns data in format: {"0": {computer data}, "1": {computer data}, ...}
    const computers = Object.values(glpiResponse.data);

    if (computers.length > 0) {
      existsInGLPI = true;
      glpiComputerId = computers[0].id || computers[0].ID;
      glpiComputerData = computers[0];
      console.log(`✓ DUPLICATE FOUND: ${hostName} already exists in GLPI as ID ${glpiComputerId}`);
    } else {
      console.log(`✓ NEW HOST: ${hostName} not found in GLPI`);
    }
  } else {
    console.log(`⚠ No response from GLPI for ${hostName}, treating as new`);
  }

  return {
    json: {
      // Original data
      ...requestData,

      // Duplicate check results
      duplicate_check: {
        exists_in_glpi: existsInGLPI,
        glpi_computer_id: glpiComputerId,
        glpi_computer_data: glpiComputerData,
        serial: serial,
        checked_at: new Date().toISOString()
      },

      // Flag for downstream processing
      is_duplicate: existsInGLPI,
      should_process: !existsInGLPI, // Only process if not a duplicate

      // Keep session token for downstream
      session_token: requestData.session_token,

      // For grouping
      batch_id: Date.now()
    }
  };
});

// Separate duplicates from non-duplicates
const allItems = results.map(r => r.json);
const nonDuplicates = allItems.filter(item => !item.is_duplicate);
const duplicates = allItems.filter(item => item.is_duplicate);

console.log('\n=== DUPLICATE CHECK SUMMARY ===');
console.log(`Total hosts checked: ${allItems.length}`);
console.log(`Non-duplicates (to process): ${nonDuplicates.length}`);
console.log(`Duplicates (to skip): ${duplicates.length}`);

// Log duplicates
if (duplicates.length > 0) {
  console.log('\n--- DUPLICATES SKIPPED ---');
  duplicates.forEach(dup => {
    console.log(`- ${dup.host_name} (Serial: ${dup.serial_number}) → GLPI ID: ${dup.duplicate_check.glpi_computer_id}`);
  });
}

// Return non-duplicates for processing
const nonDuplicateHosts = nonDuplicates.map(item => item.original_host);

// Also return summary data
return [{
  json: {
    // Original FOG data structure
    success: true,
    data: {
      hosts: nonDuplicateHosts,
      total_hosts: nonDuplicateHosts.length,
      valid_hosts: nonDuplicateHosts.length,
      invalid_hosts: 0,
      retrieved_at: new Date().toISOString()
    },
    metadata: {
      module_name: "FOG_Host_Retrieval",
      module_version: "1.0.0",
      execution_id: "duplicate-checked",
      items_processed: nonDuplicateHosts.length,
      source: "fog_api",
      duplicates_skipped: duplicates.length
    },

    // Session token for downstream
    session_token: nonDuplicates[0]?.session_token,

    // ===== PRESERVED FOG HOSTS DATA FOR DOWNSTREAM NODES =====
    // This survives through all merge nodes since no other node writes to this key
    _preserved_fog_data: {
      hosts: nonDuplicateHosts,
      total_hosts: nonDuplicateHosts.length,
      valid_hosts: nonDuplicateHosts.length
    },

    // Summary
    duplicate_check_summary: {
      total_checked: allItems.length,
      duplicates_found: duplicates.length,
      to_process: nonDuplicateHosts.length,
      duplicates: duplicates.map(d => ({
        host_name: d.host_name,
        serial: d.serial_number,
        glpi_id: d.duplicate_check.glpi_computer_id
      }))
    }
  }
}];

return items.map(item => {
  const data = item.json;
  const glpiDataJson = JSON.stringify(data.glpi_data);

  console.log(`Processing: ${data.host_name} (${data.inventory_number})`);

  return {
    json: {
      computer_name: data.host_name,
      inventory_number: data.inventory_number,
      serial_number: data.serial_number,
      fog_host_id: data.fog_host_id,
      status: data.status,
      glpi_data_json: glpiDataJson
    }
  };
});

const extractData = $node["Extract ids"].json;
const postgresOutput = $json;

// Access the nested computermodels_id
const modelId = extractData._full_data?.glpi_data?.computermodels_id || null;

return {
  success: postgresOutput.success,
  inventory_number: extractData.inventory_number,
  computermodels_id: modelId
};

parameters.query:
SELECT 
  EXISTS(
    SELECT 1 FROM created_computers 
    WHERE serial_number = '{{ $json.serial_number }}'
  ) AS is_duplicate,
  '{{ $json.serial_number }}' AS serial_number;
